Java<pre><code>@Controller // oppure @RestController se vuoi sempre JSON
@RequestMapping("/servlet")
public class CicsWebInterfaceServlet extends HttpServlet {
    private static Logger log = LoggerFactory.getLogger(CicsWebInterfaceServlet.class);
    @Autowired
    private SupernautRegion region;

    @RequestMapping(value = {"/**"}, method = {RequestMethod.GET, RequestMethod.POST})
    public void handle(HttpServletRequest request, HttpServletResponse response) throws IOException {
        run(request, response);
    }

    void run(HttpServletRequest request, HttpServletResponse response) throws IOException {
        try {
            String uri = buildUri(request);

            NChar ca = new NChar(uri.length())
                    .initial(uri)
                    .allocate();

            BackgroundTerminalHandler bkgTerm = new BackgroundTerminalHandler(region, null);
            User user = null;
            Task t = region.newTask(StartCode.Dpl, bkgTerm, new ServletPctEntry(CWISAMP.class.getName()))
                    .servlet(this, request, response)
                    .data(ca.getAddress().getStorage().getBytes(), ca.length());
            if (user != null) {
                t.user(user);
            }
            var cr = t.run();
            if (!cr.isNormal()) {
                OnlineExceptionFactory.throwExceptionFor(cr.getResp());
            }
            ca.setBytes(cr.getData(), cr.getLength());
        } catch (NotauthException e) {
            log.error("servlet authentication error: {}", e.getMessage());
            throw new ResponseStatusException(HttpStatus.UNAUTHORIZED, e.getMessage(), e);
        } catch (Exception e) {
            log.error("servlet error: {}", e.getMessage());
            throw new ResponseStatusException(HttpStatus.BAD_REQUEST, e.getMessage(), e);
        }
    }

    private static String buildUri(HttpServletRequest request) {
        String uri = request.getScheme() + "://" +
                request.getServerName() +
                ":" +
                request.getServerPort() +
                request.getRequestURI();
        if (request.getQueryString() != null) {
            uri += "?" + request.getQueryString();                     // "?lastname=Fox&amp;age=30"
        }
        return uri;
    }
}
</code></pre>

Java<pre><code>@Override
class WorkingStorage extends NGroup {
    public StructMqtm mqtm = new StructMqtm();
    final NInt16 intoLen = new NInt16();
    public NChar message = new NChar(40).initial(NChar.Space);
}

@ProgramStorage
final WorkingStorage WS = new WorkingStorage();

protected int procedure(AbstractNField dfhcommarea) throws ContextException {
    WS.intoLen.setValue(WS.mqtm.length());
    supernaut.retrieve()
            .into(WS.mqtm)
            .length(WS.intoLen)
            .nohandle()
            .exec();

    var mq = supernaut.jms();
    var hconn = new JmsConnection();
    JmsObjectDescriptor od = new JmsObjectDescriptor();
    od.setQueue(WS.mqtm.getQName().toString().trim());
    JmsObject hobj = null;
    try {
        hobj = mq.open(hconn, od, IJmsMqApi.OpenMode.InputShared);
        int l = mq.get(hconn, hobj, new MessageDescriptor(), new JmsGetOptions(), WS.message, WS.message.length());
        supernaut.trace("received %d bytes [%s]", l, WS.message.getString(0, l));
        mq.close(hconn, hobj, 0);
    } catch (JmsMqApiException e) {
        throw new RuntimeException(e);
    } catch (JMSException e) {
        throw new RuntimeException(e);
    }
    return 0;
}
</code></pre>

